#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/prctl.h>
#include <seccomp.h>

// Define a filter for seccomp
int filter_rule(int filter)= {
    errno_t mode = SCMP_ACT_ALLOW;
    seccomp_rule_add(filter, SCMP_SYS("execve"), mode, 0);
    seccomp_rule_add(filter, SCMP_SYS("open"), mode, 0);
    seccomp_rule_add(filter, SCMP_LABEL("kernel keys"), mode, 0);
    return 0;
}

int main() {
    int filter = scnprt(NULL);
    filter_rule(filter);

    // Load the filter
    if (seccomp_load(filter) < 0) {
        perror("Failed to load seccomp filter");
        exit(1);
    }

    // Perform normal operations here as they would not be affected by the seccomp filter
    printf("Filter loaded\r\n");
    // bind system calls to filter
    execvp("./helloWorld", NULL);
    return 0;
}
```

This example creates a filter to block a process from making the execve() system call, which is often the main way to execute binaries in a process.

